    get_items_from_bom: function (frm) {
    var d = new frappe.ui.Dialog({
        title: __("Get Items from BOM"),
        fields: [
            {
                    fieldname: "bom",
                    fieldtype: "Link",
                    label: __("BOM"),
                    options: "BOM",
                    reqd: 1,
                    get_query: function () {
                            return { filters: { docstatus: 1, is_active: 1 } };
                    },
            },
            {
                    fieldname: "warehouse",
                    fieldtype: "Link",
                    label: __("For Warehouse"),
                    options: "Warehouse",
                    reqd: 1,
            },
            { fieldname: "qty", fieldtype: "Float", label: __("Quantity"), reqd: 1, default: 1 },
            {
                    fieldname: "fetch_exploded",
                    fieldtype: "Check",
                    label: __("Fetch exploded BOM (including sub-assemblies)"),
                    default: 1,
            },
        ],
        primary_action_label: __("Get Items"),
        primary_action(values) {
            if (!values) return;
            values["company"] = frm.doc.company;
            if (!frm.doc.company) frappe.throw(__("Company field is required"));
            frappe.call({
                method: "erpnext.manufacturing.doctype.bom.bom.get_bom_items",
                args: values,
                callback: function (r) {
                    if (!r.message) {
                            frappe.throw(__("BOM does not contain any stock item"));
                    } else {
                        erpnext.utils.remove_empty_first_row(frm, "items");
                        $.each(r.message, function (i, item) {
                            var d = frappe.model.add_child(cur_frm.doc, "Material Request Item", "items");
                            d.item_code = item.item_code;
                            d.item_name = item.item_name;
                            d.description = item.description;
                            d.warehouse = values.warehouse;
                           d.uom = item.stock_uom;
                            d.stock_uom = item.stock_uom;
                            d.conversion_factor = 1;
                            d.qty = item.qty;
                            d.project = item.project;
                            d.bom_no = values.bom;
                            d.custom_bom_qty = item.qty;
                        });

                        // Track which BOM was used for procurement
                        frm.set_value('custom_procurement_bom', values.bom);
                    }
                    d.hide();
                    refresh_field("items");
                },
            });
        },
    });

    d.show();
},
validate: function(frm) {
   // Skip if already confirmed once
    if (frm.skip_bom_qty_check) return;

    let items_exceeding = frm.doc.items.filter(i => i.bom_no && i.custom_bom_qty && i.qty > i.custom_bom_qty);

    // Show warning only once (avoid duplicate from recursive save in check_bom_qty)
    if (items_exceeding.length > 0 && !frm._bom_qty_warning_shown) {
        frm._bom_qty_warning_shown = true;
